var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"운명과 숙명에 대해, 들어본 적 있나?","JPN":"運命と宿命について、聞いたことはある？","ENG":"Have you heard of fate and destiny?","TWN":"聽說過命運和宿命嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"둘 다 비슷한 말이지만 여기서 말하는 운명과 숙명은 뜻이 조금 달라.","JPN":"どちらも似たような言葉だけど、ここで言う運命と宿命は少し意味合いが違う。","ENG":"While they may sound synonymous, their meanings are a bit different.","TWN":"雖然兩個詞意思接近，但這裡所說的命運和宿命有些不同。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"운명은 세계에서부터 너에게로 비롯되는 것.","JPN":"運命は世界からあなたへ与えられるもの。","ENG":"Fate is thrust upon you by the world...","TWN":"命運是世界會帶給你的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 숙명은 너 자신이 스스로에게 부여하는 의무지.","JPN":"そして宿命はあなた自身が自らに与える義務。","ENG":"whereas destiny is created by your decisions.","TWN":"但宿命是你自身賦予自己的義務。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"어렵게 생각할 필요 없어, 그냥 취향이라고 생각하면 돼.","JPN":"難しく考える必要はない。ただの好みと思えばいい。","ENG":"Don't let it go over your head. Just think of it as a matter of preference.","TWN":"沒必要想得太複雜，你可以想成是一種喜好就好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"운명은 엄마가 해 주는 맛없는 영양식이고, 숙명은 네가 먹고 싶지만 몸에는 나쁜 정크 푸드지.","JPN":"運命はお母さんが作ってくれる不味い栄養食で、宿命は君が食べたいけど体には悪いジャンクフードだよ。","ENG":"Fate is like the bland healthy food your mom makes for you... while destiny is like the junk food you'd rather have.","TWN":"命運就像母親為了孩子做的不合口味但卻營養的餐點，宿命則是你自己喜歡吃的垃圾食物。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"굳이 차이가 있다면...... 운명은 피할 수 있지만, 숙명은 그럴 수 없어.","JPN":"あえて違いを言うなら……運命は避けられるけど、宿命は避けられない。","ENG":"If there's a real difference between the two... You can avoid your fate, but not your destiny.","TWN":"非要區分的話……命運可以避開，但宿命沒辦法逃避。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"애초에 숙명은 네 욕망이 만들어내는 거니까.","JPN":"宿命はあなたの欲望が作り出すものだからね。","ENG":"Destiny is forged from your own desires, after all.","TWN":"因為宿命是你的慾望所製造出來的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"누구에게나 정해진 운명과 숙명이 있어.","JPN":"誰にでも決まった運命と宿命がある。","ENG":"Everyone has their own fate and destiny.","TWN":"每個人都有指定的命運和宿命。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그것들을 하나씩 극복해 가면서 강해지고, 성장하게 되지.","JPN":"そして、それらを一つずつ克服していくことで強くなり、成長する。","ENG":"You grow stronger as you overcome them, one at a time.","TWN":"通過克服這些可以變得更強並逐漸成長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 강해진다고, 성장한다고 해서 그 결과가 자신이 원하던 모습이라는 보장은 없어.","JPN":"でも成長したからといって、その結果が自分が望んでいたものだという保障はないよ。","ENG":"But there's no guarantee you'll end up where you want to be.","TWN":"但是就算變強或者成長，也沒辦法保證那個結果是自身所希望的樣子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"오히려 그렇지 않은 경우가 더 많지.","JPN":"むしろ、そうでない場合が多い。","ENG":"If anything, the opposite is often true.","TWN":"反而出現意料之外的情況比較多一些。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 누군가는 자신의 운명과 숙명에......","JPN":"だからある人は自分の運命や宿命に……","ENG":"So some people wish to fetter their own fate and destiny...","TWN":"所以有些人會對自己的命運和宿命……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"혹은 변치 않길 바라는 타인에게 족쇄를 채우려 들기도 하지.","JPN":"あるいは、変わらないでほしい誰かに足かせをはめようとする。","ENG":"Or those of others whom they wish would not change.","TWN":"或者給不願改變的其他人戴上枷鎖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 이런 따분한 얘기를 하냐고?","JPN":"なぜこんなくだらないことを言うのかって？","ENG":"What's with all this boring rambling, you ask?","TWN":"不明白為什麼要講這種枯燥的故事？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"간단해, 네 숙명에 채워져 있던 구속구가 부서지기 직전이거든.","JPN":"簡単だよ。あなたの宿命につけられていた拘束具が壊れる直前なんだ。","ENG":"It's simple. The fetters on your destiny are about to break.","TWN":"很簡單，因為加在你宿命上的拘束器即將破碎。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"물론 클리포트 인자를 사용하기 시작한 시점에서 이미 금이 가 있었고, 언젠가는 부서질 예정이었어.","JPN":"確かにクリフォト・ファクターを使用し始めた時点ですでにひびが入っていたし、いずれは壊れる予定だった。","ENG":"It was already cracked when you started using the Qliphoth Factor. It was bound to break eventually.","TWN":"只要使用逆卡巴拉因子就會產生裂痕，然後終有一天會破碎。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 지금은 시기가 너무 일러.","JPN":"でも……まだ時期が早い。","ENG":"But... It's too early now.","TWN":"但……現在時機尚早。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 원한다면, 구속구를 다시 복원해 줄 수는 있어.","JPN":"あなたが望むなら、拘束具を復元することができる。","ENG":"If you'd like, I could restore the fetters for you.","TWN":"只要你願意，我可以幫你將拘束器還原。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"어떤 바보 같은 스승님처럼, 변해 버린 자신의 모습에 절망하지 않도록.","JPN":"とあるバカな師匠のように、変わってしまった自分の姿に絶望しないように。","ENG":"That would prevent you from despairing at your changed self, like a certain foolish Master did.","TWN":"我可不會像某個傻瓜一樣，對於發生變化的自己產生絕望。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 지금 이 순간 네가 소중하다고 여기는 것들을 지키고 싶다면......","JPN":"でも、今この瞬間あなたが大切だと思うものを守りたいなら……","ENG":"But if you wish to protect all you hold dear right now...","TWN":"但如果你想守護在此瞬間認為寶貴的東西……"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"숙명을 겪고 변해 갈 스스로의 모습에 후회하지 않을 자신이 있다면......","JPN":"宿命を経て変わっていく自らの姿に後悔しない自信があるのなら……","ENG":"And if you're confident that you won't regret facing your destiny...","TWN":"如果你有信心對經歷宿命後而發生變化的自己不後悔的話……"},"stage":{"bg":"MAINSTREAM_432010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"너의 숙명을 해방시켜 줄게.","JPN":"あなたの宿命を解放してあげる。","ENG":"I will free you.","TWN":"我可以幫你解放你的宿命。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 이제 선택할 시간이야.","JPN":"さあ、選択する時だよ。","ENG":"Now, it's time to make a choice.","TWN":"那麼，現在你該做出選擇了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"네 대답은......","JPN":"あなたの答えは……","ENG":"What's your answer?","TWN":"你的回答是……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐? 바보 같은 소리 하지 말라고?","JPN":"え？　バカを言うんじゃないって？","ENG":"Huh? This is a stupid question?","TWN":"什麼？你說我是多此一問？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"이미 예전에 대답했었다, 라......","JPN":"もうすでに答えている、と……","ENG":"Oh, so you've already given your answer before...","TWN":"早就在之前做出過抉擇了……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"그래. 그랬었지.","JPN":"ああ、そうだったね。","ENG":"Right. You have, indeed.","TWN":"對，沒錯。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"소중한 사람들과, 그들이 살아갈 세상을 지키기 위해서라면 변화를 두려워하지 않는다고 말이야.","JPN":"大切な人々と、彼らが生きていく世界を守るためなら変化を恐れない、とね。","ENG":"You said you're not afraid of change if it means you can protect those you care about and the world they live in.","TWN":"為了守護珍愛的人以及他們生活的世界，你不畏懼變化。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"여전하네.","JPN":"相変わらずだね。","ENG":"You haven't changed at all.","TWN":"你還是老樣子。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"확실히 넌 바보일지 몰라도 겁쟁이는 아니야.","JPN":"確かにあなたはバカかもしれないけど、臆病者じゃあない。","ENG":"You may be a fool, but you're no coward.","TWN":"你可能是個傻瓜，但絕不是膽小鬼。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아. 그렇다면......","JPN":"いいよ。それなら……","ENG":"Very good. In that case...","TWN":"好吧，這樣的話……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 걸어 갈 길에 행운이 함께하기를.","JPN":"あなたの歩む道に幸運がありますように。","ENG":"Best of luck on your journey.","TWN":"我希望在你前進的道路上幸運與你同在。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};